// ---------- name helpers (fuzzy matching) ----------
const normalizeName = (str) =>
  (str || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^A-Z0-9 ]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

const levenshtein = (a, b) => {
  const s = a;
  const t = b;
  const m = s.length;
  const n = t.length;
  if (m === 0) return n;
  if (n === 0) return m;

  const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;

  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      const cost = s[i - 1] === t[j - 1] ? 0 : 1;
      dp[i][j] = Math.min(
        dp[i - 1][j] + 1,
        dp[i][j - 1] + 1,
        dp[i - 1][j - 1] + cost
      );
    }
  }
  return dp[m][n];
};

const isFuzzyMatch = (a, b) => {
  const A = normalizeName(a);
  const B = normalizeName(b);
  if (!A || !B) return false;
  if (A === B) return true;
  if (A.includes(B) || B.includes(A)) return true;

  const dist = levenshtein(A, B);
  const maxLen = Math.max(A.length, B.length);
  const ratio = dist / maxLen;
  return ratio <= 0.2;
};

const FindImmatriculationOrChasisNumberScreen = () => {
  const navigation = useNavigation();
  const { verification, setVerification, setFormProgress } =
    useContext(AppContext);
  const { updateCurrentStep } = useFormNavigation();
  const { t } = useTranslation(); // Initialize translation hook

  const [input, setInput] = useState("");
  const [errorMessage, setErrorMessage] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [nameMatches, setNameMatches] = useState(false);
  const [showNotFoundModal, setShowNotFoundModal] = useState(false);
  const [searchedValue, setSearchedValue] = useState(""); 

  // New loading states for modal buttons
  const [isContinuingVerification, setIsContinuingVerification] = useState(false);
  const [isRegisteringFresh, setIsRegisteringFresh] = useState(false);

  useEffect(() => {
    updateCurrentStep("find_immatriculation_or_chasis_number_screen");
  }, []);

  useEffect(() => {
    const t = setTimeout(() => {
      if (input.trim()) {
        setVerification((p) => ({
          ...p,
          numeimma: input.trim().toUpperCase(),
        }));
      }
    }, 800);
    return () => clearTimeout(t);
  }, [input]);

  const allFieldsFilled = input.trim().length > 0;

  const validateInput = (raw) => {
    const plate = raw.trim().toUpperCase();

    const regionCodes = new Set([
      "AD",
      "CE",
      "EN",
      "ES",
      "LT",
      "NO",
      "NW",
      "OU",
      "SU",
      "SW",
    ]);

    const isOldPlateFormat =
      plate.length === 7 &&
      regionCodes.has(plate.substring(0, 2)) &&
      /^\d{4}$/.test(plate.substring(2, 6)) &&
      /[A-Z]/.test(plate.substring(6));

    const isNewPlateFormat =
      plate.length === 7 &&
      regionCodes.has(plate.substring(0, 2)) &&
      /^\d{3}$/.test(plate.substring(2, 5)) &&
      /^[A-Z]{2}$/.test(plate.substring(5, 7));

    const isChassisSixDigitFormat =
      plate.startsWith("CH") &&
      plate.length === 8 &&
      /^\d{6}$/.test(plate.substring(2));

    const isFullChassis = plate.length === 17 && /^[A-Z0-9]+$/.test(plate);

    const ok =
      isOldPlateFormat ||
      isNewPlateFormat ||
      isChassisSixDigitFormat ||
      isFullChassis;

    if (!ok) {
      setErrorMessage(t("verification.invalidFormat"));
    } else {
      setErrorMessage(null);
    }

    return ok;
  };

  const handleSearch = async () => {
    setResult(null);
    setErrorMessage(null);
    setNameMatches(false);

    if (!validateInput(input)) return;

    setIsLoading(true);

    try {
      const immatric = input.trim().toUpperCase();
      setSearchedValue(immatric);

      const response = await axios.post(
        `${API_BASE_URL}/api/verification/find-immatriculation`,
        { input: immatric }
      );

      // ✅ correct shape
      const payload = response.data; // { found: true/false, data: {...} }

      if (!payload?.found) {
        // ✅ open the "register afresh" modal
        setShowNotFoundModal(true);
        return;
      }

      // ✅ this is the actual returned data
      const row = payload.data;

      setResult(row);

      const assureFromDb = row?.ASSURE || "";

      const ownerInfo = verification?.owner;
      if (!ownerInfo) {
        console.log(
          "No ownerInfo in context - FindImmatriculationOrChasisNumber.js"
        );
        setNameMatches(false);
        setShowModal(true); // still show modal, but mismatch
        return;
      }

      let enteredOwnerName = "";
      const ownerType = (ownerInfo.type || "").toUpperCase();

      if (ownerType === "PHYSIQUE") {
        enteredOwnerName = `${ownerInfo.firstName || ""} ${
          ownerInfo.lastName || ""
        }`.trim();
      } else if (ownerType === "MORALE") {
        enteredOwnerName = (ownerInfo.organizationName || "").trim();
      }

      console.log("assure: - FindImmatriculationOrChasisNumber.js:1747", assureFromDb);
      console.log("ownerInfo: - FindImmatriculationOrChasisNumber.js:1748", ownerInfo);
      console.log("enteredOwnerName: - FindImmatriculationOrChasisNumber.js:1749", enteredOwnerName);

      const match =
        !!enteredOwnerName && isFuzzyMatch(assureFromDb, enteredOwnerName);

      setNameMatches(match);
      setShowModal(true);

      // ✅ mark step as completed now that we have a valid result
      setFormProgress((prev) => ({
        ...prev,
        completedSteps: [
          ...new Set([
            ...(prev.completedSteps || []),
            "find_immatriculation_or_chasis_number_screen",
          ]),
        ],
      }));
    } catch (e) {
      console.log("Erreur backend /api/verification/findimmatriculation: - FindImmatriculationOrChasisNumber.js:1768", e);
      setResult(null);
      setShowModal(false);
      setErrorMessage(t("verification.networkError"));
    } finally {
      setIsLoading(false);
    }
  };

  const immatriculation = result?.NUMEIMMA ?? "";
  const assure = result?.ASSURE ?? "";
  const dateEcheance = result?.DATEECHE ?? "";

const handleContinueVerification = async () => {
  setIsContinuingVerification(true);

  const owner = verification?.owner;

  const ownerIsIncomplete =
    !owner ||
    ((owner.type || "").toUpperCase() === "PHYSIQUE" &&
      (!owner.firstName || !owner.lastName)) ||
    ((owner.type || "").toUpperCase() === "MORALE" && !owner.organizationName);

  if (ownerIsIncomplete) {
    setErrorMessage(t("verification.ownerInfoIncomplete"));
    setShowModal(false);
    setIsContinuingVerification(false);
    return;
  }

  try {
    console.log(
      `Owner info being sent to backend is ${JSON.stringify(verification.owner)}`
    );

    const resp = await axios.post(`${API_BASE_URL}/api/verification/start`, {
      numeimma: (immatriculation || "").trim().toUpperCase(),
      owner: verification.owner,
      driver: verification.driver || null,
    });

    const data = resp.data;

    // ✅ new backend contract
    if (!data?.success || !data?.verificationId) {
      setShowModal(false);
      setErrorMessage(
        data?.error || t("verification.serverResponseInvalid")
      );
      setIsContinuingVerification(false);
      return;
    }

    // ✅ store returned ids (folderPrefix removed)
    setVerification((prev) => ({
      ...prev,
      verificationId: data.verificationId,
      vehicleId: data.vehicleId ?? prev.vehicleId ?? null,
      numeimma: (immatriculation || "").trim().toUpperCase(),
    }));

    // Upload pending owner ID if exists (non-blocking)
    try {
      const pendingOwnerId = verification?.pendingUploads?.ownerId;
      if (pendingOwnerId) {
        await uploadVerificationDocument(
          data.verificationId,
          "OWNER_ID",
          pendingOwnerId
        );

        setVerification((prev) => ({
          ...prev,
          pendingUploads: {
            ...(prev.pendingUploads || {}),
            ownerId: null,
          },
        }));
      }
    } catch (e) {
      console.log(
        "Owner ID upload failed (OWNER_ID):",
        e?.message || e
      );
    }

    // setFormProgress((prev) => ({
    //   ...prev,
    //   completedSteps: [
    //     ...new Set([
    //       ...(prev.completedSteps || []),
    //       "find_immatriculation_or_chasis_number_screen",
    //     ]),
    //   ],
    //   currentStep: "vehicle_admin_info",
    // }));
    const completionStatus = await getPaymentCompletionStatus(data.verificationId);
    if (completionStatus.completed) {
      console.log('✅ Payment already completed, skipping to vehicle admin info - FindImmatriculationOrChasisNumber.js:1867');

      setFormProgress((prev) => ({
        ...prev,
        completedSteps: [
          ...new Set([
            ...(prev.completedSteps || []),
            "find_immatriculation_or_chasis_number_screen",
            "payment_screen", // Mark payment screen as completed too
          ]),
        ],
        currentStep: "vehicle_admin_info",
      }));

      setShowModal(false);
      setIsContinuingVerification(false);

      // Skip payment and go directly to vehicle admin info
      navigation.navigate("vehicle_admin_info", {
        verificationId: data.verificationId,
        vehicleId: data.vehicleId,
        status: data.status,
      });
    } else {
      // Payment not completed, go to payment screen
      setFormProgress((prev) => ({
        ...prev,
        completedSteps: [
          ...new Set([
            ...(prev.completedSteps || []),
            "find_immatriculation_or_chasis_number_screen",
          ]),
        ],
        currentStep: "payment_screen",
      }));

      setShowModal(false);
      setIsContinuingVerification(false);

      // Navigate to payment screen
      navigation.navigate("payment_screen", {
        verificationId: data.verificationId,
        vehicleId: data.vehicleId,
      });
    }
  } catch (e) {
    console.log("Error /api/verification/start: - FindImmatriculationOrChasisNumber.js:1913", e);
    setShowModal(false);
    setIsContinuingVerification(false);

    // Better error message if backend returns something useful
    const msg =
      e?.response?.data?.message ||
      e?.response?.data?.error ||
      t("verification.serverError");

    setErrorMessage(msg);
  }
};


  const handleGoBack = () => {
    const ownerType = (verification?.owner?.type || "").toUpperCase();

    if (ownerType === "PHYSIQUE" || ownerType === "MORALE") {
      navigation.navigate("vehicle_owner_form_screen");
    } else {
      navigation.navigate("not_vehicle_owner_form_screen");
    }
  };

  const handleRegisterAfresh = async () => {
    // ✅ Vehicle not found -> collect minimal vehicle + owner info first
    const plateOrChassis = (searchedValue || input || "").trim().toUpperCase();
    setShowModal(false)
    setShowNotFoundModal(false);
    navigation.navigate("vehicle_not_found_info", {
      identifier: plateOrChassis,
    });
  };

    const handleRegisterNOtMatchedUser = async () => {
    // ✅ Vehicle not found -> collect minimal vehicle + owner info first
    const plateOrChassis = (searchedValue || input || "").trim().toUpperCase();
    setShowModal(false)
    navigation.navigate("vehicle_not_matched_info", {
      identifier: plateOrChassis,
    });
  };


  return (
    <View style={styles.screen}>
      <Header />


      <ScrollView contentContainerStyle={styles.scroll}>
        <Pressable style={styles.backButton} onPress={handleGoBack}>
          <Text style={styles.backIcon}>←</Text>
        </Pressable>
        <Text style={styles.title}>{t("verification.title")}</Text>
        <Text style={styles.subtitle}>
          {t("verification.subtitle")}
        </Text>

        <View style={styles.card}>
          <Text style={styles.label}>{t("verification.inputLabel")}</Text>

          <TextInput
            value={input}
            onChangeText={(t) => {
              setInput(t);
              setErrorMessage(null);
            }}
            placeholder={t("verification.inputPlaceholder")}
            placeholderTextColor="#9CA3AF"
            autoCapitalize="characters"
            style={[styles.input, errorMessage && { borderColor: COLORS.error }]}
          />

          {errorMessage && <Text style={styles.errorText}>{errorMessage}</Text>}

          <TouchableOpacity
            onPress={handleSearch}
            disabled={!allFieldsFilled || isLoading}
            style={[
              styles.cta,
              (!allFieldsFilled || isLoading) && { opacity: 0.5 },
            ]}
          >
            {isLoading ? (
              <ActivityIndicator color="#FFF" />
            ) : (
              <Text style={styles.ctaText}>{t("verification.searchButton")}</Text>
            )}
          </TouchableOpacity>
        </View>
      </ScrollView>

      <Modal visible={showModal && !!result} transparent animationType="fade">
        <View style={styles.modalOverlay}>
          <View style={styles.modalCard}>
            <Text style={styles.modalTitle}>{t("verification.resultFound")}</Text>

            <InfoRow label={t("verification.registration")} value={immatriculation} />
            <InfoRow label={t("verification.insured")} value={assure} />
            <InfoRow label={t("verification.expiry")} value={dateEcheance} />

            {nameMatches ? (
              <>
                <Text style={styles.successText}>
                  {t("verification.infoMatches")}
                </Text>
                <TouchableOpacity
                  style={[
                    styles.modalPrimary,
                    isContinuingVerification && styles.buttonLoading
                  ]}
                  onPress={handleContinueVerification}
                  disabled={isContinuingVerification}
                >
                  {isContinuingVerification ? (
                    <ActivityIndicator color="#FFF" size="small" />
                  ) : (
                    <Text style={styles.modalPrimaryText}>
                      {t("verification.continueVerification")}
                    </Text>
                  )}
                </TouchableOpacity>
              </>
            ) : (
              <>
                <Text style={styles.errorTextCenter}>
                  {t("verification.infoDoesNotMatch")}
                </Text>
                <TouchableOpacity
                  style={styles.modalSecondary}
                  onPress={handleRegisterNOtMatchedUser}
                >
                  <Text style={styles.modalSecondaryText}>{t("common.continue")}</Text>
                </TouchableOpacity>
              </>
            )}
          </View>
        </View>
      </Modal>

      <Modal visible={showNotFoundModal} transparent animationType="fade">
        <View style={styles.modalOverlay}>
          <View style={styles.modalCard}>
            <Text style={styles.modalTitle}>{t("verification.vehicleNotFound")}</Text>

            <Text style={{ textAlign: "center", color: COLORS.textMuted, marginBottom: 14 }}>
              {t("verification.vehicleNotFoundMessage")}
            </Text>

            <InfoRow label={t("verification.input")} value={searchedValue || input} />

            <TouchableOpacity 
              style={[
                styles.modalPrimary,
                isRegisteringFresh && styles.buttonLoading
              ]} 
              onPress={handleRegisterAfresh}
              disabled={isRegisteringFresh}
            >
              {isRegisteringFresh ? (
                <ActivityIndicator color="#FFF" size="small" />
              ) : (
                <Text style={styles.modalPrimaryText}>{t("common.continue")}</Text>
              )}
            </TouchableOpacity>

            <View style={{ height: 10 }} />

            <TouchableOpacity
              style={styles.modalSecondary}
              onPress={() => setShowNotFoundModal(false)}
              disabled={isRegisteringFresh}
            >
              <Text style={[
                styles.modalSecondaryText,
                isRegisteringFresh && { opacity: 0.5 }
              ]}>{t("common.cancel")}</Text>
            </TouchableOpacity>
          </View>
        </View>
      </Modal>

    </View>
  );
};

